/// <summary>
/// Extension class of <c>WmsPickingList_OrderPickDP</c> for text block management
/// </summary>
[ExtensionOf(classStr(WmsPickingList_OrderPickDP))]
final class FWFTextBlockWmsPickingList_OrderPickDP_Extension
{
}

Method.Source:
protected void initPickingListOrderPickTmp(WMSPickingList_OrderPickTmp _pickingListOrderPickTmp, WMSOrderTrans _orderTrans)
{
    next initPickingListOrderPickTmp(_pickingListOrderPickTmp, _orderTrans);

    if (this.wmsPickingList_OrderPickTmp.ItemId)
    {
        FWFTextBlockReportTextInit::newParameters(this.wmsPickingList_OrderPickTmp, _orderTrans.wmsOrder()).addTexts();
    }
    else
    {
        FWFTextBlockReportTextInit::newParameters(this.wmsPickingList_OrderPickTmp, this.wmsPickingRoute).addTexts();
    }
}
